from flask import Flask, request, jsonify
import psycopg2
import psycopg2.extras

app = Flask(__name__)

def get_db_connection():
    return psycopg2.connect(
        dbname="yourdbname",
        user="yourusername",
        password="yourpassword",
        host="localhost"
    )

@app.route('/query', methods=['POST'])
def query():
    data = request.json
    table = data.get('table', '')
    columns = data.get('columns', '*')
    filters = data.get('filters', '')

    if not table:
        return jsonify({'error': 'Table name is required'}), 400

    columns_sql = ', '.join(psycopg2.sql.Identifier(col) for col in columns) if isinstance(columns, list) else '*'
    filters_sql = psycopg2.sql.SQL(filters) if filters else psycopg2.sql.SQL('')

    query = psycopg2.sql.SQL('SELECT {} FROM {} WHERE {}').format(
        psycopg2.sql.SQL(columns_sql),
        psycopg2.sql.Identifier(table),
        filters_sql
    ) if filters else psycopg2.sql.SQL('SELECT {} FROM {}').format(
        psycopg2.sql.SQL(columns_sql),
        psycopg2.sql.Identifier(table)
    )

    try:
        conn = get_db_connection()
        with conn.cursor(cursor_factory=psycopg2.extras.DictCursor) as cur:
            cur.execute(query)
            result = cur.fetchall()
        conn.close()
        return jsonify(result)
    except Exception as e:
        return jsonify({'error': str(e)}), 500

if __name__ == '__main__':
    app.run(debug=True)